import { type ReactNode, useRef } from 'react';

import { type Store, createStore } from '../../../../../../core/store/store.js';
import { RangeLegendStore } from '../context/RangeLegendStore.js';
import type { RangeLegendState } from '../types/state.js';

export const StoreProvider = ({ children }: { children: ReactNode }) => {
  const storeRef = useRef<Store<RangeLegendState> | null>(null);

  storeRef.current = createStore({ hoveredMarkerId: null } as RangeLegendState);

  return (
    <RangeLegendStore.Provider value={storeRef.current}>
      {children}
    </RangeLegendStore.Provider>
  );
};
